    public void handleTrade(Client client, Object message)
    {
        //
        //     {
        //         "e": "trade",
        //         "E": 1776104608321,
        //         "s": "ETHUSDT",
        //         "d": [
        //             {
        //                 "T": 1776104608298,
        //                 "t": "41099265-7985-4f4c-af93-2cc3bc1cf13b",
        //                 "p": "2225.15",
        //                 "q": "0.02525",
        //                 "v": "56.1850375",
        //                 "m": false
        //             }
        //         ]
        //     }
        //
        Object market = this.getMarketFromClientAndMessage(client, message);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object messageHash = Helpers.add("trade::", symbol);
        if (!Helpers.isTrue((Helpers.inOp(this.trades, symbol))))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            Helpers.addElementToObject(this.trades, symbol, new ArrayCache(((Number)limit).intValue()));
        }
        Object tradesArray = Helpers.GetValue(this.trades, symbol);
        Object data = this.safeList(message, "d", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object newTrades = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object rawTrade = this.safeDict(data, i, new java.util.HashMap<String, Object>() {{}});
            Object trade = this.parseWsTrade(rawTrade, market);
            ((java.util.List<Object>)newTrades).add(trade);
        }
        Object sorted = this.sortBy(newTrades, "timestamp");
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(sorted)); j++)
        {
            Object sortedTrade = Helpers.GetValue(sorted, j);
            Helpers.callDynamically(tradesArray, "append", new Object[]{sortedTrade});
        }
        Helpers.addElementToObject(this.trades, symbol, tradesArray);
        client.resolve(tradesArray, messageHash);
    }

