    public void handleMyTrades(Client client, Object message)
    {
        //
        // spot
        //     {
        //         e: 'fill',
        //         E: 1776174283564,
        //         v: 83,
        //         msgEvent: 'OrderUpdate',
        //         d: [
        //             {
        //                 id: '738928502249620072',
        //                 symbol: 'DOGEUSDT',
        //                 baseCoin: 'DOGE',
        //                 quoteCoin: 'USDT',
        //                 orderId: '738928502174122600',
        //                 orderSide: 'SELL',
        //                 fillSize: '200.0',
        //                 fillValue: '19.098000',
        //                 fillFee: '0.01909800',
        //                 direction: 'TAKER',
        //                 createdTime: '1776174283564',
        //                 updatedTime: '1776174283564'
        //             }
        //         ]
        //     }
        //
        // swap
        //     {
        //         "id": "738957755401896296",
        //         "coin": "USDT",
        //         "symbol": "DOGEUSDT",
        //         "orderId": "738957755376730472",
        //         "marginMode": "CROSSED",
        //         "separatedMode": "COMBINED",
        //         "separatedOpenOrderId": "0",
        //         "positionSide": "LONG",
        //         "orderSide": "BUY",
        //         "fillSize": "100",
        //         "fillValue": "9.59500",
        //         "fillFee": "0.00767600",
        //         "liquidateFee": "0",
        //         "realizePnl": "0",
        //         "direction": "TAKER",
        //         "createdTime": "1776181258059",
        //         "updatedTime": "1776181258059"
        //     }
        //
        if (Helpers.isTrue(Helpers.isEqual(this.myTrades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            this.myTrades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object trades = this.myTrades;
        Object data = this.safeList(message, "d", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object symbols = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object trade = this.safeDict(data, i, new java.util.HashMap<String, Object>() {{}});
            Object parsed = this.parseWsMyTrade(trade);
            Object symbol = Helpers.GetValue(parsed, "symbol");
            Helpers.addElementToObject(symbols, symbol, true);
            Helpers.callDynamically(trades, "append", new Object[]{parsed});
        }
        Object messageHash = "myTrades";
        Object symbolKeys = Helpers.objectKeys(symbols);
        Object market = this.getMarketFromSymbols(symbolKeys);
        if (Helpers.isTrue(Helpers.GetValue(market, "contract")))
        {
            messageHash = "myContractTrades";
        }
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(symbolKeys)); j++)
        {
            Object symbol = Helpers.GetValue(symbolKeys, j);
            Object symbolMessageHash = Helpers.add(Helpers.add(messageHash, "::"), symbol);
            client.resolve(trades, symbolMessageHash);
        }
        client.resolve(trades, messageHash);
    }

    public Object parseWsMyTrade(Object trade, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         id: '738928502249620072',
        //         symbol: 'DOGEUSDT',
        //         baseCoin: 'DOGE',
        //         quoteCoin: 'USDT',
        //         orderId: '738928502174122600',
        //         orderSide: 'SELL',
        //         fillSize: '200.0',
        //         fillValue: '19.098000',
        //         fillFee: '0.01909800',
        //         direction: 'TAKER',
        //         createdTime: '1776174283564',
        //         updatedTime: '1776174283564'
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "createdTime");
        Object marketId = this.safeString(trade, "symbol");
        Object marketType = "spot";
        Object positionSide = this.safeString(trade, "positionSide");
        if (Helpers.isTrue(!Helpers.isEqual(positionSide, null)))
        {
            marketType = "swap";
        }
        market = this.safeMarket(marketId, null, null, marketType);
        Object side = this.safeStringLower(trade, "orderSide");
        Object fee = null;
        Object commission = this.safeString(trade, "fillFee");
        if (Helpers.isTrue(!Helpers.isEqual(commission, null)))
        {
            Object commissionAsset = this.safeString(trade, "coin");
            Object feeCurrency = this.safeCurrencyCode(commissionAsset);
            if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
                {
                    feeCurrency = Helpers.GetValue(market, "base");
                } else
                {
                    feeCurrency = Helpers.GetValue(market, "quote");
                }
            }
            final Object finalCommission = commission;
            final Object finalFeeCurrency = feeCurrency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalCommission );
                put( "currency", finalFeeCurrency );
            }};
        }
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", WeexCore.this.safeString(trade, "id") );
            put( "timestamp", timestamp );
            put( "datetime", WeexCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", WeexCore.this.safeString(trade, "orderId") );
            put( "type", WeexCore.this.safeString(trade, "type") );
            put( "side", finalSide );
            put( "takerOrMaker", WeexCore.this.safeStringLower(trade, "direction") );
            put( "price", null );
            put( "amount", WeexCore.this.safeString(trade, "fillSize") );
            put( "cost", WeexCore.this.safeString(trade, "fillValue") );
            put( "fee", finalFee );
        }});
    }

